                          <Plus size={18} />
                      </button>
                   </div>
                </div>

                {/* Duration */}
                <div>
                   <label className="text-xs uppercase tracking-wider text-white/50 font-medium mb-3 block">Duration per Step</label>
                   <div className="bg-white/5 rounded-2xl p-2 border border-white/5">
                        <div className="flex items-center justify-between mb-4 px-2 pt-2">
                             <button onClick={() => setBulkDuration(Math.max(60, bulkDuration - 60))} className="p-2 text-white/40 hover:text-white"><Minus size={16} /></button>
                             <span className="font-mono text-2xl font-bold text-white tracking-wider">{formatTime(bulkDuration)}</span>
                             <button onClick={() => setBulkDuration(bulkDuration + 60)} className="p-2 text-white/40 hover:text-white"><Plus size={16} /></button>
                        </div>
                        <div className="flex items-center justify-center gap-1.5 overflow-x-auto no-scrollbar pb-1">
                            {PRESETS.slice(0, 5).map((preset) => (
                                <button
                                    key={preset}
                                    onClick={() => setBulkDuration(preset)}
                                    className={`w-9 h-9 rounded-lg flex items-center justify-center text-[10px] font-medium border transition-all ${
                                        bulkDuration === preset
                                        ? 'bg-white/20 text-white border-white/20'
                                        : 'bg-white/5 text-white/30 border-white/5 hover:bg-white/10 hover:text-white/60'
                                    }`}
                                >
                                    {preset < 3600 ? `${preset / 60}m` : `${preset / 3600}h`}
                                </button>
                            ))}
                        </div>
                   </div>
                </div>

                {/* Actions */}
                <button 
                  onClick={handleBulkAdd}
                  className="w-full h-14 rounded-xl bg-white/10 hover:bg-white/15 border border-white/10 text-white font-semibold flex items-center justify-center gap-2 transition-all active:scale-[0.98] shadow-lg shadow-black/40"
                >
                    <Plus size={18} className="text-green-400" />
                    Add {bulkCount} Steps
                </button>
              </div>
           </div>
        </div>
      )}

      {/* Step List */}
      <div className="flex-1 min-h-0 overflow-y-auto no-scrollbar px-4 space-y-3 pb-4 relative z-10">
        {steps.map((step, index) => (
            <div 
                key={step.id} 
                className="group relative flex flex-col p-4 rounded-2xl bg-white/5 border border-white/5 hover:bg-white/10 hover:border-white/10 transition-all duration-300"
            >
                {/* Top Row: Index, Reorder, Name, Actions */}
                <div className="flex items-center gap-3 mb-3">
                    {/* Index & Reorder Group */}
                    <div className="flex items-center gap-2 shrink-0">
                        {/* Index Badge */}
                        <div className="w-6 h-6 shrink-0 rounded-full bg-white/10 flex items-center justify-center text-xs font-mono text-white/50">
                            {index + 1}
                        </div>
                        {/* Stacked Arrows */}
                        <div className="flex flex-col gap-0.5">
                            <button 
                                onClick={() => moveStepUp(index)}
                                disabled={index === 0}
                                className={`text-white/40 hover:text-white disabled:opacity-20 disabled:hover:text-white/40 transition-colors flex items-center justify-center h-3 w-4 ${index === 0 ? 'cursor-not-allowed' : ''}`}
                            >
                                <ChevronUp size={14} />
                            </button>
                            <button 
                                onClick={() => moveStepDown(index)}
                                disabled={index === steps.length - 1}
                                className={`text-white/40 hover:text-white disabled:opacity-20 disabled:hover:text-white/40 transition-colors flex items-center justify-center h-3 w-4 ${index === steps.length - 1 ? 'cursor-not-allowed' : ''}`}
                            >
                                <ChevronDown size={14} />
                            </button>
                        </div>
                    </div>

                    <input 
                        type="text" 
                        value={step.label}
                        onChange={(e) => updateStep(step.id, { label: e.target.value })}
                        className="bg-transparent border-none text-white font-medium focus:ring-0 p-0 text-base placeholder-white/20 flex-1 min-w-0"
                        placeholder="Step Name"
                    />

                    <div className="flex items-center gap-1 shrink-0">
                        <button 
                            onClick={() => duplicateStep(step.id)}
                            className="text-white/20 hover:text-blue-400 transition-colors p-2 rounded-full hover:bg-white/5"
                            title="Duplicate Step"
                        >
                            <Copy size={16} />
                        </button>
                        <button 
                            onClick={() => removeStep(step.id)}
                            className={`text-white/20 hover:text-red-400 transition-colors p-2 rounded-full hover:bg-white/5 ${steps.length <= 1 ? 'opacity-0 pointer-events-none' : ''}`}
                        >
                            <Trash2 size={16} />
                        </button>
                    </div>
                </div>

                {/* Middle Row: Duration Counter */}
                <div className="flex items-center justify-between bg-black/20 rounded-xl p-1.5 mb-2 border border-white/5">
                    <button 
                        onClick={() => adjustStepDuration(step.id, -15)}
                        className="w-8 h-8 flex items-center justify-center rounded-lg bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors"
                    >
                        <Minus size={14} />
                    </button>

                    <span className="font-mono text-lg font-bold text-white/90 tracking-wider">
                        {formatTime(step.duration)}
                    </span>

                    <button 
                        onClick={() => adjustStepDuration(step.id, 15)}
                        className="w-8 h-8 flex items-center justify-center rounded-lg bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors"
                    >
                        <Plus size={14} />
                    </button>
                </div>

                {/* Bottom Row: Quick Presets */}
                <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1">
                    {PRESETS.map((preset) => (
                        <button
                            key={preset}
                            onClick={() => updateStep(step.id, { duration: preset })}
                            className={`flex-shrink-0 px-2.5 py-1 rounded-md text-[10px] font-medium border transition-all ${
                                step.duration === preset
                                ? 'bg-white/20 text-white border-white/20'
                                : 'bg-white/5 text-white/40 border-white/5 hover:bg-white/10 hover:text-white/60'
                            }`}
                        >
                            {preset < 3600 ? `${preset / 60}m` : `${preset / 3600}h`}
                        </button>
                    ))}
                </div>
            </div>
        ))}
        {/* Spacer for bottom controls */}
        <div className="h-4"></div>
      </div>

      {/* Editor Controls - Aligned with Timer View */}
      <div className="w-full px-4 pb-2 shrink-0 z-20">
          <div className={controlBoxClass}>
             <div className="flex items-center gap-3">
                 <button 
                    onClick={resetEditor}
                    className={`${resetBtn} w-16`}
                    title="Reset Sequence"
                 >
                    <RotateCcw size={20} />
                 </button>

                 <button
                   onClick={toggleTimer}
                   className={`${startBtn} flex-1 gap-2 font-bold tracking-wide`}
                 >
                   <Play size={20} className="fill-current" />
                   <span>START</span>
                 </button>
             </div>
          </div>
      </div>

    </div>
  );
};

export default SequenceView;

import React, { useState, useEffect, useRef } from 'react';
import { Play, Pause, Plus, Trash2, RotateCcw, ArrowRight, Minus, Layers, X, Check, Copy, Briefcase, Sparkles, Save, ChevronDown, ChevronUp } from 'lucide-react';
import CircularProgress from './CircularProgress';
import { formatTime } from '../utils/time';
import { playTone } from '../utils/soundEngine';
import { SoundId } from '../types';
import { useWakeLock } from '../hooks/useWakeLock';

interface SequenceStep {
  id: string;
  duration: number; // seconds
  label: string;
}

interface SavedSequence {
    id: string;
    name: string;
    steps: SequenceStep[];
}

interface SequenceViewProps {
  soundId: SoundId;
}

const PRESETS = [60, 180, 300, 600, 1500, 3600];
const STORAGE_KEY = 'chronos_saved_sequences';

const SequenceView: React.FC<SequenceViewProps> = ({ soundId }) => {
  // --- State ---
  const [steps, setSteps] = useState<SequenceStep[]>([
    { id: '1', duration: 1500, label: 'Work' },
    { id: '2', duration: 300, label: 'Rest' },
  ]);

  const [activeStepIndex, setActiveStepIndex] = useState<number>(0);
  const [timeLeft, setTimeLeft] = useState<number>(1500);
  const [isRunning, setIsRunning] = useState<boolean>(false);
  const [isPaused, setIsPaused] = useState<boolean>(false);

  // --- Saved Sequences State ---
  const [savedSequences, setSavedSequences] = useState<SavedSequence[]>([]);
  const [isSavedListExpanded, setIsSavedListExpanded] = useState(false);
  // Responsive collapsed count: 2 for mobile, 3 for tablet/desktop
  const [collapsedCount, setCollapsedCount] = useState(2);

  // --- Bulk Add State ---
  const [isBulkModalOpen, setIsBulkModalOpen] = useState(false);
  const [bulkCount, setBulkCount] = useState(4);
  const [bulkDuration, setBulkDuration] = useState(300); // Default 5m

  const intervalRef = useRef<number | null>(null);

  // --- Wake Lock ---
  useWakeLock(isRunning && !isPaused);

  // --- Initialize ---
  useEffect(() => {
    // Load from local storage
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
        try {
            setSavedSequences(JSON.parse(saved));
        } catch (e) {
            console.error("Failed to parse saved sequences");
        }
    }

    // Handle responsive resize for saved flows list
    const handleResize = () => {
        // Tailwind 'sm' breakpoint is 640px
        if (window.innerWidth >= 640) {
            setCollapsedCount(3);
        } else {
            setCollapsedCount(2);
        }
    };

    handleResize(); // Initial set
    window.addEventListener('resize', handleResize);

    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- Timer Logic ---
  useEffect(() => {
    if (isRunning && !isPaused) {
      intervalRef.current = window.setInterval(() => {
        setTimeLeft((prev) => {
          if (prev <= 1) {
            // Step Finished
            playTone(soundId);
            handleNextStep();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    } else {
      if (intervalRef.current) clearInterval(intervalRef.current);
    }

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [isRunning, isPaused, activeStepIndex, steps, soundId]);

  const handleNextStep = () => {
    if (activeStepIndex < steps.length - 1) {
      // Move to next step
      const nextIndex = activeStepIndex + 1;
      setActiveStepIndex(nextIndex);
      setTimeLeft(steps[nextIndex].duration);
    } else {
      // Sequence Complete
      setIsRunning(false);
      setIsPaused(false);
      setActiveStepIndex(0);
      setTimeLeft(steps[0].duration);
    }
  };

  // --- Handlers ---
  const toggleTimer = () => {
    if (!isRunning) {
      // Starting from scratch or reset
      setIsRunning(true);
      setIsPaused(false);
      if (timeLeft === 0 || activeStepIndex === 0) { 
          // Reset time left to the first step's duration on fresh start
          setTimeLeft(steps[0].duration);
      }
    } else {
      setIsPaused(!isPaused);
    }
  };

  const resetSequence = () => {
    setIsRunning(false);
    setIsPaused(false);
    setActiveStepIndex(0);
    setTimeLeft(steps[0].duration);
  };

  const resetEditor = () => {
    if (window.confirm('Reset sequence to default?')) {
        setSteps([
            { id: '1', duration: 1500, label: 'Work' },
            { id: '2', duration: 300, label: 'Rest' },
        ]);
        setActiveStepIndex(0);
        setTimeLeft(1500);
        setIsRunning(false);
        setIsPaused(false);
    }
  };

  // --- Saving Handlers ---
  const saveCurrentSequence = () => {
      const name = window.prompt("Name your flow:", `Flow ${savedSequences.length + 1}`);
      if (!name) return;

      const newSequence: SavedSequence = {
          id: Date.now().toString(),
          name,
          steps: [...steps] // Clone current steps
      };

      const updatedList = [newSequence, ...savedSequences];
      setSavedSequences(updatedList);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedList));
  };

  const deleteSavedSequence = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      if(window.confirm("Delete this saved flow?")) {
        const updatedList = savedSequences.filter(s => s.id !== id);
        setSavedSequences(updatedList);
        localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedList));
      }
  };

  const loadSavedSequence = (saved: SavedSequence) => {
      setSteps(saved.steps);
      setActiveStepIndex(0);
      setTimeLeft(saved.steps[0].duration);
      setIsRunning(false);
      setIsPaused(false);
  };

  // --- Editor Handlers ---
  const addStep = () => {
    const newStep: SequenceStep = {
      id: Date.now().toString(),
      duration: 300,
      label: 'Focus',
    };
    setSteps([...steps, newStep]);
  };

  const removeStep = (id: string) => {
    if (steps.length <= 1) return;
    setSteps(steps.filter(s => s.id !== id));
  };

  const duplicateStep = (id: string) => {
    const index = steps.findIndex(s => s.id === id);
    if (index === -1) return;

    const stepToCopy = steps[index];
    const newStep: SequenceStep = {
        ...stepToCopy,
        id: `${Date.now()}-${Math.random()}`,
        label: stepToCopy.label
    };

    const newSteps = [...steps];
    newSteps.splice(index + 1, 0, newStep);
    setSteps(newSteps);
  };

  const moveStepUp = (index: number) => {
    if (index === 0) return;
    const newSteps = [...steps];
    // Swap current step with previous step
    [newSteps[index - 1], newSteps[index]] = [newSteps[index], newSteps[index - 1]];
    setSteps(newSteps);
  };

  const moveStepDown = (index: number) => {
    if (index === steps.length - 1) return;
    const newSteps = [...steps];
    // Swap current step with next step
    [newSteps[index], newSteps[index + 1]] = [newSteps[index + 1], newSteps[index]];
    setSteps(newSteps);
  };

  const updateStep = (id: string, updates: Partial<SequenceStep>) => {
    setSteps(steps.map(s => s.id === id ? { ...s, ...updates } : s));
  };

  const adjustStepDuration = (id: string, amount: number) => {
    const step = steps.find(s => s.id === id);
    if (step) {
      const newDuration = Math.max(10, step.duration + amount); // Min 10s
      updateStep(id, { duration: newDuration });
      // If we are editing the step currently ready to play (and not running), update preview
      if (!isRunning && steps[activeStepIndex].id === id) {
          setTimeLeft(newDuration);
      }
    }
  };

  // --- Template Handlers ---
  const loadTemplate = (type: 'yoga-3' | 'yoga-5' | 'work') => {
      const now = Date.now();
      let newSteps: SequenceStep[] = [];

      if (type === 'yoga-3') {
          newSteps = Array.from({length: 4}).map((_, i) => ({
              id: `${now}-${i}`,
              duration: 180, // 3 minutes
              label: `Flow ${i + 1}`
          }));
      } else if (type === 'yoga-5') {
          newSteps = Array.from({length: 4}).map((_, i) => ({
              id: `${now}-${i}`,
              duration: 300, // 5 minutes
              label: `Flow ${i + 1}`
          }));
      } else if (type === 'work') {
          newSteps = [
              { id: `${now}-1`, duration: 1500, label: 'Work' }, // 25 min
              { id: `${now}-2`, duration: 300, label: 'Break' } // 5 min
          ];
      }

      setSteps(newSteps);
      setActiveStepIndex(0);
      setTimeLeft(newSteps[0].duration);
      setIsRunning(false);
      setIsPaused(false);
  };

  // --- Bulk Handlers ---
  const handleBulkAdd = () => {
    const startCount = steps.length + 1;
    const newSteps: SequenceStep[] = Array.from({ length: bulkCount }).map((_, i) => ({
        id: `${Date.now()}-${i}`,
        duration: bulkDuration,
        label: `Step ${startCount + i}`,
    }));

    // Append steps instead of replacing
    setSteps([...steps, ...newSteps]);
    setIsBulkModalOpen(false);
  };

  // --- Styles ---
  // Shared with TimerView for consistency
  const controlBoxClass = "bg-gray-900/40 backdrop-blur-xl border border-white/10 p-3 sm:p-4 rounded-[1.5rem] shadow-2xl shadow-black/50";
  const glassButton = "relative h-14 w-full rounded-2xl flex items-center justify-center transition-all duration-300 ease-out backdrop-blur-md border border-white/5 overflow-hidden group";
  const startBtn = `${glassButton} bg-white/10 hover:bg-white/15 border-white/10 text-green-400 hover:shadow-[0_0_20px_rgba(74,222,128,0.2)] active:scale-[0.98]`;
  const resetBtn = `${glassButton} bg-white/5 hover:bg-white/10 active:scale-[0.98] text-white/80 hover:text-white hover:border-white/20`;

  // --- Render ---

  // 1. RUNNING MODE
  if (isRunning || (activeStepIndex > 0 && isPaused)) {
    const currentStep = steps[activeStepIndex];
    const progress = currentStep.duration > 0 ? timeLeft / currentStep.duration : 0;
    const nextStep = activeStepIndex < steps.length - 1 ? steps[activeStepIndex + 1] : null;

    return (
      <div className="flex flex-col items-center h-full w-full max-w-md mx-auto relative animate-in fade-in zoom-in duration-300">

        {/* Header Indicator */}
        <div className="absolute top-0 w-full flex justify-between px-4 py-2 text-xs text-white/40 uppercase tracking-widest font-medium z-10">
            <span>Running</span>
            <span>{activeStepIndex + 1} / {steps.length}</span>
        </div>

        {/* Main Circle */}
        <div className="flex-1 min-h-0 w-full flex flex-col justify-center items-center py-2 relative">
            {/* Glow behind timer matching TimerView */}
            <div className="absolute w-[200px] h-[200px] bg-white/5 rounded-full blur-3xl pointer-events-none"></div>

            <CircularProgress progress={progress} color="text-white/90">
                <div className="text-5xl sm:text-6xl font-mono font-bold tracking-wider text-white drop-shadow-2xl">
                    {formatTime(timeLeft)}
                </div>
                <div className="text-white/50 mt-2 text-sm sm:text-base font-medium tracking-wider">
                    {currentStep.label}
                </div>
            </CircularProgress>

            {/* Next Step Preview */}
            {nextStep && (
                <div className="absolute bottom-4 flex items-center gap-2 text-white/30 text-sm">
                    <span>Next: {nextStep.label}</span>
                    <ArrowRight size={14} />
                    <span>{formatTime(nextStep.duration)}</span>
                </div>
            )}
        </div>

        {/* Controls - Matching TimerView */}
        <div className="w-full px-4 pb-2 shrink-0">
            <div className={controlBoxClass}>
                <div className="flex items-center justify-center gap-4">
                    <button 
                        onClick={resetSequence}
                        className={`${resetBtn} w-16`} // Explicit width for uniformity
                    >
                        <RotateCcw size={20} />
                    </button>

                    <button
                        onClick={toggleTimer}
                        className={`flex-1 ${
                            isPaused 
                            ? 'bg-green-500/10 border-green-500/20 text-green-400 hover:bg-green-500/20 shadow-[0_0_15px_rgba(74,222,128,0.1)]' 
                            : 'bg-red-500/10 border-red-500/20 text-red-400 hover:bg-red-500/20 shadow-[0_0_15px_rgba(239,68,68,0.1)]'
                        } ${glassButton}`}
                    >
                        {isPaused ? <Play size={24} className="ml-1 fill-current" /> : <Pause size={24} className="fill-current" />}
                    </button>
                </div>
            </div>
        </div>
      </div>
    );
  }

  // 2. EDITOR MODE

  // Logic for display items (Responsive)
  const displaySavedSequences = isSavedListExpanded 
    ? savedSequences 
    : savedSequences.slice(0, collapsedCount);

  return (
    <div className="flex flex-col h-full w-full max-w-md mx-auto pt-2 animate-in slide-in-from-bottom-4 duration-500 relative">

      {/* Editor Header - Simplified */}
      <div className="px-4 pb-4 flex justify-between items-center relative z-10 shrink-0">
          <button 
              onClick={saveCurrentSequence}
              className="flex items-center justify-center gap-2 px-3 py-1.5 rounded-lg bg-white/5 hover:bg-white/10 text-xs font-semibold text-white/80 transition-colors border border-white/10"
              title="Save Flow"
          >
             <Save size={14} /> Save Sequence
          </button>

          <div className="flex items-center gap-2">
            <button 
                onClick={() => setIsBulkModalOpen(true)}
                className="flex items-center justify-center gap-2 px-3 py-1.5 rounded-lg bg-white/5 hover:bg-white/10 text-xs font-semibold text-white/80 transition-colors border border-white/10"
                title="Batch Add"
            >
               <Layers size={14} /> Batch
            </button>
            <button 
                onClick={addStep}
                className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-white/10 hover:bg-white/20 text-xs font-semibold text-white/90 transition-colors border border-white/10"
            >
                <Plus size={14} /> Step
            </button>
          </div>
      </div>

      {/* Template Quick Actions */}
      <div className="px-4 pb-4 flex gap-3 overflow-x-auto no-scrollbar z-10 shrink-0">
         <button 
            onClick={() => loadTemplate('yoga-3')}
            className="flex-shrink-0 flex items-center gap-2 px-3 py-2 rounded-xl bg-purple-500/10 border border-purple-500/20 hover:bg-purple-500/20 text-purple-200 text-xs font-semibold transition-all active:scale-95"
         >
            <Sparkles size={14} />
            Yoga (3m)
         </button>
         <button 
            onClick={() => loadTemplate('yoga-5')}
            className="flex-shrink-0 flex items-center gap-2 px-3 py-2 rounded-xl bg-purple-500/10 border border-purple-500/20 hover:bg-purple-500/20 text-purple-200 text-xs font-semibold transition-all active:scale-95"
         >
            <Sparkles size={14} />
            Yoga (5m)
         </button>
         <button 
            onClick={() => loadTemplate('work')}
            className="flex-shrink-0 flex items-center gap-2 px-3 py-2 rounded-xl bg-blue-500/10 border border-blue-500/20 hover:bg-blue-500/20 text-blue-200 text-xs font-semibold transition-all active:scale-95"
         >
            <Briefcase size={14} />
            Work (25/5)
         </button>
      </div>

      {/* Custom Saved Flows (Expandable) */}
      {savedSequences.length > 0 && (
          <div className="px-4 pb-2 z-10 shrink-0">
            <div className="flex items-center justify-between mb-2">
                <span className="text-xs uppercase tracking-wider text-white/40 font-bold">My Flows</span>
                {savedSequences.length > collapsedCount && (
                    <button 
                        onClick={() => setIsSavedListExpanded(!isSavedListExpanded)}
                        className="text-[10px] text-white/50 hover:text-white flex items-center gap-1 uppercase tracking-wider"
                    >
                        {isSavedListExpanded ? 'Show Less' : 'Show All'}
                        {isSavedListExpanded ? <ChevronUp size={12}/> : <ChevronDown size={12} />}
                    </button>
                )}
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                {displaySavedSequences.map((seq) => (
                    <div 
                        key={seq.id}
                        onClick={() => loadSavedSequence(seq)}
                        className="group relative flex items-center justify-between px-3 py-2 rounded-xl bg-white/5 border border-white/5 hover:bg-white/10 hover:border-white/10 transition-all cursor-pointer active:scale-[0.98]"
                    >
                        <div className="flex items-center gap-1 min-w-0 flex-1">
                            <span className="text-xs font-semibold text-white truncate">
                                {seq.name} <span className="text-white/50 font-normal">({seq.steps.length})</span>
                            </span>
                        </div>
                        <button 
                            onClick={(e) => deleteSavedSequence(e, seq.id)}
                            className="shrink-0 p-1 text-white/20 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity ml-1"
                        >
                            <X size={12} />
                        </button>
                    </div>
                ))}
            </div>
          </div>
      )}

      {/* Bulk Add Modal */}
      {isBulkModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
           <div className="w-full max-w-sm bg-[#111] border border-white/10 rounded-3xl p-6 shadow-2xl animate-in zoom-in-95 duration-200">

              <div className="flex justify-between items-center mb-6">
                 <h3 className="text-lg font-bold text-white">Batch Add Steps</h3>
                 <button onClick={() => setIsBulkModalOpen(false)} className="p-2 text-white/40 hover:text-white rounded-full hover:bg-white/10 transition-colors">
                    <X size={20} />
                 </button>
              </div>

              <div className="space-y-6">
                {/* Steps Count */}
                <div>
                   <label className="text-xs uppercase tracking-wider text-white/50 font-medium mb-3 block">Number of Steps</label>
                   <div className="flex items-center justify-between bg-white/5 rounded-2xl p-2 border border-white/5">
                      <button onClick={() => setBulkCount(Math.max(1, bulkCount - 1))} className="w-12 h-12 flex items-center justify-center rounded-xl bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors">
                          <Minus size={18} />
                      </button>
                      <span className="text-2xl font-mono font-bold text-white">{bulkCount}</span>
                      <button onClick={() => setBulkCount(Math.min(50, bulkCount + 1))} className="w-12 h-12 flex items-center justify-center rounded-xl bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors">
                          <Plus size={18} />
                      </button>
                   </div>
                </div>

                {/* Duration */}
                <div>
                   <label className="text-xs uppercase tracking-wider text-white/50 font-medium mb-3 block">Duration per Step</label>
                   <div className="bg-white/5 rounded-2xl p-2 border border-white/5">
                        <div className="flex items-center justify-between mb-4 px-2 pt-2">
                             <button onClick={() => setBulkDuration(Math.max(60, bulkDuration - 60))} className="p-2 text-white/40 hover:text-white"><Minus size={16} /></button>
                             <span className="font-mono text-2xl font-bold text-white tracking-wider">{formatTime(bulkDuration)}</span>
                             <button onClick={() => setBulkDuration(bulkDuration + 60)} className="p-2 text-white/40 hover:text-white"><Plus size={16} /></button>
                        </div>
                        <div className="flex items-center justify-center gap-1.5 overflow-x-auto no-scrollbar pb-1">
                            {PRESETS.slice(0, 5).map((preset) => (
                                <button
                                    key={preset}
                                    onClick={() => setBulkDuration(preset)}
                                    className={`w-9 h-9 rounded-lg flex items-center justify-center text-[10px] font-medium border transition-all ${
                                        bulkDuration === preset
                                        ? 'bg-white/20 text-white border-white/20'
                                        : 'bg-white/5 text-white/30 border-white/5 hover:bg-white/10 hover:text-white/60'
                                    }`}
                                >
                                    {preset < 3600 ? `${preset / 60}m` : `${preset / 3600}h`}
                                </button>
                            ))}
                        </div>
                   </div>
                </div>

                {/* Actions */}
                <button 
                  onClick={handleBulkAdd}
                  className="w-full h-14 rounded-xl bg-white/10 hover:bg-white/15 border border-white/10 text-white font-semibold flex items-center justify-center gap-2 transition-all active:scale-[0.98] shadow-lg shadow-black/40"
                >
                    <Plus size={18} className="text-green-400" />
                    Add {bulkCount} Steps
                </button>
              </div>
           </div>
        </div>
      )}

      {/* Step List */}
      <div className="flex-1 min-h-0 overflow-y-auto no-scrollbar px-4 space-y-3 pb-4 relative z-10">

        {/* Step Count Header */}
        <div className="flex items-center justify-between px-1 mb-1">
             <span className="text-xs font-bold text-white/40 uppercase tracking-wider">Sequence</span>
             <span className="text-[10px] font-mono text-white/60 bg-white/5 px-2 py-0.5 rounded border border-white/5">
                 {steps.length} Steps
             </span>
        </div>

        {steps.map((step, index) => (
            <div 
                key={step.id} 
                className="group relative flex flex-col p-4 rounded-2xl bg-white/5 border border-white/5 hover:bg-white/10 hover:border-white/10 transition-all duration-300"
            >
                {/* Top Row: Index, Name, Arrows, Actions */}
                <div className="flex items-center gap-3 mb-3">
                    {/* Index Badge */}
                    <div className="w-6 h-6 shrink-0 rounded-full bg-white/10 flex items-center justify-center text-xs font-mono text-white/50">
                        {index + 1}
                    </div>

                    {/* Title Input */}
                    <input 
                        type="text" 
                        value={step.label}
                        onChange={(e) => updateStep(step.id, { label: e.target.value })}
                        className="bg-transparent border-none text-white font-medium focus:ring-0 p-0 text-base placeholder-white/20 flex-1 min-w-0"
                        placeholder="Step Name"
                    />

                    {/* Reorder Buttons (Distinct) */}
                    <div className="flex items-center gap-1 shrink-0">
                         <button 
                            onClick={() => moveStepUp(index)}
                            disabled={index === 0}
                            className={`w-7 h-7 flex items-center justify-center rounded-lg bg-white/5 hover:bg-white/15 text-white/70 disabled:opacity-20 disabled:hover:bg-white/5 transition-all ${index === 0 ? 'cursor-not-allowed' : 'active:scale-95'}`}
                            title="Move Up"
                        >
                            <ChevronUp size={16} />
                        </button>
                        <button 
                            onClick={() => moveStepDown(index)}
                            disabled={index === steps.length - 1}
                            className={`w-7 h-7 flex items-center justify-center rounded-lg bg-white/5 hover:bg-white/15 text-white/70 disabled:opacity-20 disabled:hover:bg-white/5 transition-all ${index === steps.length - 1 ? 'cursor-not-allowed' : 'active:scale-95'}`}
                            title="Move Down"
                        >
                            <ChevronDown size={16} />
                        </button>
                    </div>

                    {/* Divider */}
                    <div className="w-[1px] h-4 bg-white/10 mx-1"></div>

                    {/* Actions */}
                    <div className="flex items-center gap-1 shrink-0">
                        <button 
                            onClick={() => duplicateStep(step.id)}
                            className="text-white/20 hover:text-blue-400 transition-colors p-2 rounded-full hover:bg-white/5"
                            title="Duplicate Step"
                        >
                            <Copy size={16} />
                        </button>
                        <button 
                            onClick={() => removeStep(step.id)}
                            className={`text-white/20 hover:text-red-400 transition-colors p-2 rounded-full hover:bg-white/5 ${steps.length <= 1 ? 'opacity-0 pointer-events-none' : ''}`}
                        >
                            <Trash2 size={16} />
                        </button>
                    </div>
                </div>

                {/* Middle Row: Duration Counter */}
                <div className="flex items-center justify-between bg-black/20 rounded-xl p-1.5 mb-2 border border-white/5">
                    <button 
                        onClick={() => adjustStepDuration(step.id, -15)}
                        className="w-8 h-8 flex items-center justify-center rounded-lg bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors"
                    >
                        <Minus size={14} />
                    </button>

                    <span className="font-mono text-lg font-bold text-white/90 tracking-wider">
                        {formatTime(step.duration)}
                    </span>

                    <button 
                        onClick={() => adjustStepDuration(step.id, 15)}
                        className="w-8 h-8 flex items-center justify-center rounded-lg bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors"
                    >
                        <Plus size={14} />
                    </button>
                </div>

                {/* Bottom Row: Quick Presets */}
                <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1">
                    {PRESETS.map((preset) => (
                        <button
                            key={preset}
                            onClick={() => updateStep(step.id, { duration: preset })}
                            className={`flex-shrink-0 px-2.5 py-1 rounded-md text-[10px] font-medium border transition-all ${
                                step.duration === preset
                                ? 'bg-white/20 text-white border-white/20'
                                : 'bg-white/5 text-white/40 border-white/5 hover:bg-white/10 hover:text-white/60'
                            }`}
                        >
                            {preset < 3600 ? `${preset / 60}m` : `${preset / 3600}h`}
                        </button>
                    ))}
                </div>
            </div>
        ))}
        {/* Spacer for bottom controls */}
        <div className="h-4"></div>
      </div>

      {/* Editor Controls - Aligned with Timer View */}
      <div className="w-full px-4 pb-2 shrink-0 z-20">
          <div className={controlBoxClass}>
             <div className="flex items-center gap-3">
                 <button 
                    onClick={resetEditor}
                    className={`${resetBtn} w-16`}
                    title="Reset Sequence"
                 >
                    <RotateCcw size={20} />
                 </button>

                 <button
                   onClick={toggleTimer}
                   className={`${startBtn} flex-1 gap-2 font-bold tracking-wide`}
                 >
                   <Play size={20} className="fill-current" />
                   <span>START</span>
                 </button>
             </div>
          </div>
      </div>

    </div>
  );
};

export default SequenceView;

import React, { useState, useEffect, useRef } from 'react';
import { Play, Pause, Plus, Trash2, RotateCcw, ArrowRight, Minus, Layers, X, Check, Copy, Briefcase, Sparkles, Save, ChevronDown, ChevronUp } from 'lucide-react';
import CircularProgress from './CircularProgress';
import { formatTime } from '../utils/time';
import { playTone } from '../utils/soundEngine';
import { SoundId } from '../types';
import { useWakeLock } from '../hooks/useWakeLock';

interface SequenceStep {
  id: string;
  duration: number; // seconds
  label: string;
}

interface SavedSequence {
    id: string;
    name: string;
    steps: SequenceStep[];
}

interface SequenceViewProps {
  soundId: SoundId;
}

const PRESETS = [60, 180, 300, 600, 1500, 3600];
const STORAGE_KEY = 'chronos_saved_sequences';

const SequenceView: React.FC<SequenceViewProps> = ({ soundId }) => {
  // --- State ---
  const [steps, setSteps] = useState<SequenceStep[]>([
    { id: '1', duration: 1500, label: 'Work' },
    { id: '2', duration: 300, label: 'Rest' },
  ]);

  const [activeStepIndex, setActiveStepIndex] = useState<number>(0);
  const [timeLeft, setTimeLeft] = useState<number>(1500);
  const [isRunning, setIsRunning] = useState<boolean>(false);
  const [isPaused, setIsPaused] = useState<boolean>(false);

  // --- Saved Sequences State ---
  const [savedSequences, setSavedSequences] = useState<SavedSequence[]>([]);
  const [isSavedListExpanded, setIsSavedListExpanded] = useState(false);
  // Responsive collapsed count: 2 for mobile, 3 for tablet/desktop
  const [collapsedCount, setCollapsedCount] = useState(2);

  // --- Bulk Add State ---
  const [isBulkModalOpen, setIsBulkModalOpen] = useState(false);
  const [bulkCount, setBulkCount] = useState(4);
  const [bulkDuration, setBulkDuration] = useState(300); // Default 5m

  const intervalRef = useRef<number | null>(null);

  // --- Wake Lock ---
  useWakeLock(isRunning && !isPaused);

  // --- Initialize ---
  useEffect(() => {
    // Load from local storage
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
        try {
            setSavedSequences(JSON.parse(saved));
        } catch (e) {
            console.error("Failed to parse saved sequences");
        }
    }

    // Handle responsive resize for saved flows list
    const handleResize = () => {
        // Tailwind 'sm' breakpoint is 640px
        if (window.innerWidth >= 640) {
            setCollapsedCount(3);
        } else {
            setCollapsedCount(2);
        }
    };

    handleResize(); // Initial set
    window.addEventListener('resize', handleResize);

    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- Timer Logic ---
  useEffect(() => {
    if (isRunning && !isPaused) {
      intervalRef.current = window.setInterval(() => {
        setTimeLeft((prev) => {
          if (prev <= 1) {
            // Step Finished
            playTone(soundId);
            handleNextStep();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    } else {
      if (intervalRef.current) clearInterval(intervalRef.current);
    }

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [isRunning, isPaused, activeStepIndex, steps, soundId]);

  const handleNextStep = () => {
    if (activeStepIndex < steps.length - 1) {
      // Move to next step
      const nextIndex = activeStepIndex + 1;
      setActiveStepIndex(nextIndex);
      setTimeLeft(steps[nextIndex].duration);
    } else {
      // Sequence Complete
      setIsRunning(false);
      setIsPaused(false);
      setActiveStepIndex(0);
      setTimeLeft(steps[0].duration);
    }
  };

  // --- Handlers ---
  const toggleTimer = () => {
    if (!isRunning) {
      // Starting from scratch or reset
      setIsRunning(true);
      setIsPaused(false);
      if (timeLeft === 0 || activeStepIndex === 0) { 
          // Reset time left to the first step's duration on fresh start
          setTimeLeft(steps[0].duration);
      }
    } else {
      setIsPaused(!isPaused);
    }
  };

  const resetSequence = () => {
    setIsRunning(false);
    setIsPaused(false);
    setActiveStepIndex(0);
    setTimeLeft(steps[0].duration);
  };

  const resetEditor = () => {
    if (window.confirm('Reset sequence to default?')) {
        setSteps([
            { id: '1', duration: 1500, label: 'Work' },
            { id: '2', duration: 300, label: 'Rest' },
        ]);
        setActiveStepIndex(0);
        setTimeLeft(1500);
        setIsRunning(false);
        setIsPaused(false);
    }
  };

  // --- Saving Handlers ---
  const saveCurrentSequence = () => {
      const name = window.prompt("Name your flow:", `Flow ${savedSequences.length + 1}`);
      if (!name) return;

      const newSequence: SavedSequence = {
          id: Date.now().toString(),
          name,
          steps: [...steps] // Clone current steps
      };

      const updatedList = [newSequence, ...savedSequences];
      setSavedSequences(updatedList);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedList));
  };

  const deleteSavedSequence = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      if(window.confirm("Delete this saved flow?")) {
        const updatedList = savedSequences.filter(s => s.id !== id);
        setSavedSequences(updatedList);
        localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedList));
      }
  };

  const loadSavedSequence = (saved: SavedSequence) => {
      setSteps(saved.steps);
      setActiveStepIndex(0);
      setTimeLeft(saved.steps[0].duration);
      setIsRunning(false);
      setIsPaused(false);
  };

  // --- Editor Handlers ---
  const addStep = () => {
    const newStep: SequenceStep = {
      id: Date.now().toString(),
      duration: 300,
      label: 'Focus',
    };
    setSteps([...steps, newStep]);
  };

  const removeStep = (id: string) => {
    if (steps.length <= 1) return;
    setSteps(steps.filter(s => s.id !== id));
  };

  const duplicateStep = (id: string) => {
    const index = steps.findIndex(s => s.id === id);
    if (index === -1) return;

    const stepToCopy = steps[index];
    const newStep: SequenceStep = {
        ...stepToCopy,
        id: `${Date.now()}-${Math.random()}`,
        label: stepToCopy.label
    };

    const newSteps = [...steps];
    newSteps.splice(index + 1, 0, newStep);
    setSteps(newSteps);
  };

  const moveStepUp = (index: number) => {
    if (index === 0) return;
    const newSteps = [...steps];
    // Swap current step with previous step
    [newSteps[index - 1], newSteps[index]] = [newSteps[index], newSteps[index - 1]];
    setSteps(newSteps);
  };

  const moveStepDown = (index: number) => {
    if (index === steps.length - 1) return;
    const newSteps = [...steps];
    // Swap current step with next step
    [newSteps[index], newSteps[index + 1]] = [newSteps[index + 1], newSteps[index]];
    setSteps(newSteps);
  };

  const updateStep = (id: string, updates: Partial<SequenceStep>) => {
    setSteps(steps.map(s => s.id === id ? { ...s, ...updates } : s));
  };

  const adjustStepDuration = (id: string, amount: number) => {
    const step = steps.find(s => s.id === id);
    if (step) {
      const newDuration = Math.max(10, step.duration + amount); // Min 10s
      updateStep(id, { duration: newDuration });
      // If we are editing the step currently ready to play (and not running), update preview
      if (!isRunning && steps[activeStepIndex].id === id) {
          setTimeLeft(newDuration);
      }
    }
  };

  // --- Template Handlers ---
  const loadTemplate = (type: 'yoga-3' | 'yoga-5' | 'work') => {
      const now = Date.now();
      let newSteps: SequenceStep[] = [];

      if (type === 'yoga-3') {
          newSteps = Array.from({length: 4}).map((_, i) => ({
              id: `${now}-${i}`,
              duration: 180, // 3 minutes
              label: `Flow ${i + 1}`
          }));
      } else if (type === 'yoga-5') {
          newSteps = Array.from({length: 4}).map((_, i) => ({
              id: `${now}-${i}`,
              duration: 300, // 5 minutes
              label: `Flow ${i + 1}`
          }));
      } else if (type === 'work') {
          newSteps = [
              { id: `${now}-1`, duration: 1500, label: 'Work' }, // 25 min
              { id: `${now}-2`, duration: 300, label: 'Break' } // 5 min
          ];
      }

      setSteps(newSteps);
      setActiveStepIndex(0);
      setTimeLeft(newSteps[0].duration);
      setIsRunning(false);
      setIsPaused(false);
  };

  // --- Bulk Handlers ---
  const handleBulkAdd = () => {
    const startCount = steps.length + 1;
    const newSteps: SequenceStep[] = Array.from({ length: bulkCount }).map((_, i) => ({
        id: `${Date.now()}-${i}`,
        duration: bulkDuration,
        label: `Step ${startCount + i}`,
    }));

    // Append steps instead of replacing
    setSteps([...steps, ...newSteps]);
    setIsBulkModalOpen(false);
  };

  // --- Styles ---
  // Shared with TimerView for consistency but modified for SequenceView compactness
  const controlBoxClass = "bg-gray-900/40 backdrop-blur-xl border border-white/10 p-2 sm:p-3 rounded-[1.25rem] shadow-2xl shadow-black/50";
  const glassButton = "relative h-12 w-full rounded-xl flex items-center justify-center transition-all duration-300 ease-out backdrop-blur-md border border-white/5 overflow-hidden group";
  const startBtn = `${glassButton} bg-white/10 hover:bg-white/15 border-white/10 text-green-400 hover:shadow-[0_0_20px_rgba(74,222,128,0.2)] active:scale-[0.98]`;
  const resetBtn = `${glassButton} bg-white/5 hover:bg-white/10 active:scale-[0.98] text-white/80 hover:text-white hover:border-white/20`;

  // --- Render ---

  // 1. RUNNING MODE
  if (isRunning || (activeStepIndex > 0 && isPaused)) {
    const currentStep = steps[activeStepIndex];
    const progress = currentStep.duration > 0 ? timeLeft / currentStep.duration : 0;
    const nextStep = activeStepIndex < steps.length - 1 ? steps[activeStepIndex + 1] : null;

    return (
      <div className="flex flex-col items-center h-full w-full max-w-md mx-auto relative animate-in fade-in zoom-in duration-300">

        {/* Header Indicator */}
        <div className="absolute top-0 w-full flex justify-between px-4 py-2 text-xs text-white/40 uppercase tracking-widest font-medium z-10">
            <span>Running</span>
            <span>{activeStepIndex + 1} / {steps.length}</span>
        </div>

        {/* Main Circle */}
        <div className="flex-1 min-h-0 w-full flex flex-col justify-center items-center py-2 relative">
            {/* Glow behind timer matching TimerView */}
            <div className="absolute w-[200px] h-[200px] bg-white/5 rounded-full blur-3xl pointer-events-none"></div>

            <CircularProgress progress={progress} color="text-white/90">
                <div className="text-5xl sm:text-6xl font-mono font-bold tracking-wider text-white drop-shadow-2xl">
                    {formatTime(timeLeft)}
                </div>
                <div className="text-white/50 mt-2 text-sm sm:text-base font-medium tracking-wider">
                    {currentStep.label}
                </div>
            </CircularProgress>

            {/* Next Step Preview */}
            {nextStep && (
                <div className="absolute bottom-4 flex items-center gap-2 text-white/30 text-sm">
                    <span>Next: {nextStep.label}</span>
                    <ArrowRight size={14} />
                    <span>{formatTime(nextStep.duration)}</span>
                </div>
            )}
        </div>

        {/* Controls - Matching TimerView but compact */}
        <div className="w-full px-4 pb-2 shrink-0">
            <div className={controlBoxClass}>
                <div className="flex items-center justify-center gap-3">
                    <button 
                        onClick={resetSequence}
                        className={`${resetBtn} w-14`} // Slightly smaller width
                    >
                        <RotateCcw size={18} />
                    </button>

                    <button
                        onClick={toggleTimer}
                        className={`flex-1 ${
                            isPaused 
                            ? 'bg-green-500/10 border-green-500/20 text-green-400 hover:bg-green-500/20 shadow-[0_0_15px_rgba(74,222,128,0.1)]' 
                            : 'bg-red-500/10 border-red-500/20 text-red-400 hover:bg-red-500/20 shadow-[0_0_15px_rgba(239,68,68,0.1)]'
                        } ${glassButton}`}
                    >
                        {isPaused ? <Play size={22} className="ml-1 fill-current" /> : <Pause size={22} className="fill-current" />}
                    </button>
                </div>
            </div>
        </div>
      </div>
    );
  }

  // 2. EDITOR MODE

  // Logic for display items (Responsive)
  const displaySavedSequences = isSavedListExpanded 
    ? savedSequences 
    : savedSequences.slice(0, collapsedCount);

  return (
    <div className="flex flex-col h-full w-full max-w-md mx-auto pt-2 animate-in slide-in-from-bottom-4 duration-500 relative">

      {/* Editor Header - Simplified */}
      <div className="px-4 pb-4 flex justify-between items-center relative z-10 shrink-0">
          <button 
              onClick={saveCurrentSequence}
              className="flex items-center justify-center gap-2 px-3 py-1.5 rounded-lg bg-white/5 hover:bg-white/10 text-xs font-semibold text-white/80 transition-colors border border-white/10"
              title="Save Flow"
          >
             <Save size={14} /> Save Sequence
          </button>

          <div className="flex items-center gap-2">
            <button 
                onClick={() => setIsBulkModalOpen(true)}
                className="flex items-center justify-center gap-2 px-3 py-1.5 rounded-lg bg-white/5 hover:bg-white/10 text-xs font-semibold text-white/80 transition-colors border border-white/10"
                title="Batch Add"
            >
               <Layers size={14} /> Batch
            </button>
            <button 
                onClick={addStep}
                className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-white/10 hover:bg-white/20 text-xs font-semibold text-white/90 transition-colors border border-white/10"
            >
                <Plus size={14} /> Step
            </button>
          </div>
      </div>

      {/* Template Quick Actions */}
      <div className="px-4 pb-4 flex gap-3 overflow-x-auto no-scrollbar z-10 shrink-0">
         <button 
            onClick={() => loadTemplate('yoga-3')}
            className="flex-shrink-0 flex items-center gap-2 px-3 py-2 rounded-xl bg-purple-500/10 border border-purple-500/20 hover:bg-purple-500/20 text-purple-200 text-xs font-semibold transition-all active:scale-95"
         >
            <Sparkles size={14} />
            Yoga (3m)
         </button>
         <button 
            onClick={() => loadTemplate('yoga-5')}
            className="flex-shrink-0 flex items-center gap-2 px-3 py-2 rounded-xl bg-purple-500/10 border border-purple-500/20 hover:bg-purple-500/20 text-purple-200 text-xs font-semibold transition-all active:scale-95"
         >
            <Sparkles size={14} />
            Yoga (5m)
         </button>
         <button 
            onClick={() => loadTemplate('work')}
            className="flex-shrink-0 flex items-center gap-2 px-3 py-2 rounded-xl bg-blue-500/10 border border-blue-500/20 hover:bg-blue-500/20 text-blue-200 text-xs font-semibold transition-all active:scale-95"
         >
            <Briefcase size={14} />
            Work (25/5)
         </button>
      </div>

      {/* Custom Saved Flows (Expandable) */}
      {savedSequences.length > 0 && (
          <div className="px-4 pb-2 z-10 shrink-0">
            <div className="flex items-center justify-between mb-2">
                <span className="text-xs uppercase tracking-wider text-white/40 font-bold">My Flows</span>
                {savedSequences.length > collapsedCount && (
                    <button 
                        onClick={() => setIsSavedListExpanded(!isSavedListExpanded)}
                        className="text-[10px] text-white/50 hover:text-white flex items-center gap-1 uppercase tracking-wider"
                    >
                        {isSavedListExpanded ? 'Show Less' : 'Show All'}
                        {isSavedListExpanded ? <ChevronUp size={12}/> : <ChevronDown size={12} />}
                    </button>
                )}
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                {displaySavedSequences.map((seq) => (
                    <div 
                        key={seq.id}
                        onClick={() => loadSavedSequence(seq)}
                        className="group relative flex items-center justify-between px-3 py-2 rounded-xl bg-white/5 border border-white/5 hover:bg-white/10 hover:border-white/10 transition-all cursor-pointer active:scale-[0.98]"
                    >
                        <div className="flex items-center gap-1 min-w-0 flex-1">
                            <span className="text-xs font-semibold text-white truncate">
                                {seq.name} <span className="text-white/50 font-normal">({seq.steps.length})</span>
                            </span>
                        </div>
                        <button 
                            onClick={(e) => deleteSavedSequence(e, seq.id)}
                            className="shrink-0 p-1 text-white/20 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity ml-1"
                        >
                            <X size={12} />
                        </button>
                    </div>
                ))}
            </div>
          </div>
      )}

      {/* Bulk Add Modal */}
      {isBulkModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
           <div className="w-full max-w-sm bg-[#111] border border-white/10 rounded-3xl p-6 shadow-2xl animate-in zoom-in-95 duration-200">

              <div className="flex justify-between items-center mb-6">
                 <h3 className="text-lg font-bold text-white">Batch Add Steps</h3>
                 <button onClick={() => setIsBulkModalOpen(false)} className="p-2 text-white/40 hover:text-white rounded-full hover:bg-white/10 transition-colors">
                    <X size={20} />
                 </button>
              </div>

              <div className="space-y-6">
                {/* Steps Count */}
                <div>
                   <label className="text-xs uppercase tracking-wider text-white/50 font-medium mb-3 block">Number of Steps</label>
                   <div className="flex items-center justify-between bg-white/5 rounded-2xl p-2 border border-white/5">
                      <button onClick={() => setBulkCount(Math.max(1, bulkCount - 1))} className="w-12 h-12 flex items-center justify-center rounded-xl bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors">
                          <Minus size={18} />
                      </button>
                      <span className="text-2xl font-mono font-bold text-white">{bulkCount}</span>
                      <button onClick={() => setBulkCount(Math.min(50, bulkCount + 1))} className="w-12 h-12 flex items-center justify-center rounded-xl bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors">
                          <Plus size={18} />
                      </button>
                   </div>
                </div>

                {/* Duration */}
                <div>
                   <label className="text-xs uppercase tracking-wider text-white/50 font-medium mb-3 block">Duration per Step</label>
                   <div className="bg-white/5 rounded-2xl p-2 border border-white/5">
                        <div className="flex items-center justify-between mb-4 px-2 pt-2">
                             <button onClick={() => setBulkDuration(Math.max(60, bulkDuration - 60))} className="p-2 text-white/40 hover:text-white"><Minus size={16} /></button>
                             <span className="font-mono text-2xl font-bold text-white tracking-wider">{formatTime(bulkDuration)}</span>
                             <button onClick={() => setBulkDuration(bulkDuration + 60)} className="p-2 text-white/40 hover:text-white"><Plus size={16} /></button>
                        </div>
                        <div className="flex items-center justify-center gap-1.5 overflow-x-auto no-scrollbar pb-1">
                            {PRESETS.slice(0, 5).map((preset) => (
                                <button
                                    key={preset}
                                    onClick={() => setBulkDuration(preset)}
                                    className={`w-9 h-9 rounded-lg flex items-center justify-center text-[10px] font-medium border transition-all ${
                                        bulkDuration === preset
                                        ? 'bg-white/20 text-white border-white/20'
                                        : 'bg-white/5 text-white/30 border-white/5 hover:bg-white/10 hover:text-white/60'
                                    }`}
                                >
                                    {preset < 3600 ? `${preset / 60}m` : `${preset / 3600}h`}
                                </button>
                            ))}
                        </div>
                   </div>
                </div>

                {/* Actions */}
                <button 
                  onClick={handleBulkAdd}
                  className="w-full h-14 rounded-xl bg-white/10 hover:bg-white/15 border border-white/10 text-white font-semibold flex items-center justify-center gap-2 transition-all active:scale-[0.98] shadow-lg shadow-black/40"
                >
                    <Plus size={18} className="text-green-400" />
                    Add {bulkCount} Steps
                </button>
              </div>
           </div>
        </div>
      )}

      {/* Step List */}
      <div className="flex-1 min-h-0 overflow-y-auto no-scrollbar px-4 space-y-3 pb-4 relative z-10">

        {/* Modern Step Count Header - Elegant Line Design */}
        <div className="flex items-center gap-4 px-2 mb-2 mt-1">
             <div className="h-[1px] flex-1 bg-gradient-to-r from-transparent via-white/10 to-white/10"></div>
             <span className="text-[10px] font-mono font-medium text-white/40 uppercase tracking-[0.2em] px-3 py-1 rounded-full bg-white/5 border border-white/5 backdrop-blur-sm shadow-sm">
                 {steps.length} Steps
             </span>
             <div className="h-[1px] flex-1 bg-gradient-to-l from-transparent via-white/10 to-white/10"></div>
        </div>

        {steps.map((step, index) => (
            <div 
                key={step.id} 
                className="group relative flex flex-col p-4 rounded-2xl bg-white/5 border border-white/5 hover:bg-white/10 hover:border-white/10 transition-all duration-300"
            >
                {/* Top Row: Index, Name, Arrows, Actions */}
                <div className="flex items-center gap-3 mb-3">
                    {/* Index Badge */}
                    <div className="w-6 h-6 shrink-0 rounded-full bg-white/10 flex items-center justify-center text-xs font-mono text-white/50">
                        {index + 1}
                    </div>

                    {/* Title Input */}
                    <input 
                        type="text" 
                        value={step.label}
                        onChange={(e) => updateStep(step.id, { label: e.target.value })}
                        className="bg-transparent border-none text-white font-medium focus:ring-0 p-0 text-base placeholder-white/20 flex-1 min-w-0"
                        placeholder="Step Name"
                    />

                    {/* Reorder Buttons (Distinct) */}
                    <div className="flex items-center gap-1 shrink-0">
                         <button 
                            onClick={() => moveStepUp(index)}
                            disabled={index === 0}
                            className={`w-7 h-7 flex items-center justify-center rounded-lg bg-white/5 hover:bg-white/15 text-white/70 disabled:opacity-20 disabled:hover:bg-white/5 transition-all ${index === 0 ? 'cursor-not-allowed' : 'active:scale-95'}`}
                            title="Move Up"
                        >
                            <ChevronUp size={16} />
                        </button>
                        <button 
                            onClick={() => moveStepDown(index)}
                            disabled={index === steps.length - 1}
                            className={`w-7 h-7 flex items-center justify-center rounded-lg bg-white/5 hover:bg-white/15 text-white/70 disabled:opacity-20 disabled:hover:bg-white/5 transition-all ${index === steps.length - 1 ? 'cursor-not-allowed' : 'active:scale-95'}`}
                            title="Move Down"
                        >
                            <ChevronDown size={16} />
                        </button>
                    </div>

                    {/* Divider */}
                    <div className="w-[1px] h-4 bg-white/10 mx-1"></div>

                    {/* Actions */}
                    <div className="flex items-center gap-1 shrink-0">
                        <button 
                            onClick={() => duplicateStep(step.id)}
                            className="text-white/20 hover:text-blue-400 transition-colors p-2 rounded-full hover:bg-white/5"
                            title="Duplicate Step"
                        >
                            <Copy size={16} />
                        </button>
                        <button 
                            onClick={() => removeStep(step.id)}
                            className={`text-white/20 hover:text-red-400 transition-colors p-2 rounded-full hover:bg-white/5 ${steps.length <= 1 ? 'opacity-0 pointer-events-none' : ''}`}
                        >
                            <Trash2 size={16} />
                        </button>
                    </div>
                </div>

                {/* Middle Row: Duration Counter */}
                <div className="flex items-center justify-between bg-black/20 rounded-xl p-1.5 mb-2 border border-white/5">
                    <button 
                        onClick={() => adjustStepDuration(step.id, -15)}
                        className="w-8 h-8 flex items-center justify-center rounded-lg bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors"
                    >
                        <Minus size={14} />
                    </button>

                    <span className="font-mono text-lg font-bold text-white/90 tracking-wider">
                        {formatTime(step.duration)}
                    </span>

                    <button 
                        onClick={() => adjustStepDuration(step.id, 15)}
                        className="w-8 h-8 flex items-center justify-center rounded-lg bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors"
                    >
                        <Plus size={14} />
                    </button>
                </div>

                {/* Bottom Row: Quick Presets */}
                <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1">
                    {PRESETS.map((preset) => (
                        <button
                            key={preset}
                            onClick={() => updateStep(step.id, { duration: preset })}
                            className={`flex-shrink-0 px-2.5 py-1 rounded-md text-[10px] font-medium border transition-all ${
                                step.duration === preset
                                ? 'bg-white/20 text-white border-white/20'
                                : 'bg-white/5 text-white/40 border-white/5 hover:bg-white/10 hover:text-white/60'
                            }`}
                        >
                            {preset < 3600 ? `${preset / 60}m` : `${preset / 3600}h`}
                        </button>
                    ))}
                </div>
            </div>
        ))}
        {/* Spacer for bottom controls */}
        <div className="h-4"></div>
      </div>

      {/* Editor Controls - Compact */}
      <div className="w-full px-4 pb-2 shrink-0 z-20">
          <div className={controlBoxClass}>
             <div className="flex items-center gap-3">
                 <button 
                    onClick={resetEditor}
                    className={`${resetBtn} w-14`}
                    title="Reset Sequence"
                 >
                    <RotateCcw size={18} />
                 </button>

                 <button
                   onClick={toggleTimer}
                   className={`${startBtn} flex-1 gap-2 font-bold tracking-wide`}
                 >
                   <Play size={22} className="fill-current" />
                   <span>START</span>
                 </button>
             </div>
          </div>
      </div>

    </div>
  );
};

export default SequenceView;

import React, { useState, useEffect, useRef } from 'react';
import { Play, Pause, Plus, Trash2, RotateCcw, ArrowRight, Minus, Layers, X, Check, Copy, Briefcase, Sparkles, Save, ChevronDown, ChevronUp } from 'lucide-react';
import CircularProgress from './CircularProgress';
import { formatTime } from '../utils/time';
import { playTone } from '../utils/soundEngine';
import { SoundId } from '../types';
import { useWakeLock } from '../hooks/useWakeLock';

interface SequenceStep {
  id: string;
  duration: number; // seconds
  label: string;
}

interface SavedSequence {
    id: string;
    name: string;
    steps: SequenceStep[];
}

interface SequenceViewProps {
  soundId: SoundId;
}

const PRESETS = [60, 180, 300, 600, 1500, 3600];
const STORAGE_KEY = 'chronos_saved_sequences';

const SequenceView: React.FC<SequenceViewProps> = ({ soundId }) => {
  // --- State ---
  const [steps, setSteps] = useState<SequenceStep[]>([
    { id: '1', duration: 1500, label: 'Work' },
    { id: '2', duration: 300, label: 'Rest' },
  ]);

  const [activeStepIndex, setActiveStepIndex] = useState<number>(0);
  const [timeLeft, setTimeLeft] = useState<number>(1500);
  const [isRunning, setIsRunning] = useState<boolean>(false);
  const [isPaused, setIsPaused] = useState<boolean>(false);

  // --- Saved Sequences State ---
  const [savedSequences, setSavedSequences] = useState<SavedSequence[]>([]);
  const [isSavedListExpanded, setIsSavedListExpanded] = useState(false);
  // Responsive collapsed count: 2 for mobile, 3 for tablet/desktop
  const [collapsedCount, setCollapsedCount] = useState(2);

  // --- Bulk Add State ---
  const [isBulkModalOpen, setIsBulkModalOpen] = useState(false);
  const [bulkCount, setBulkCount] = useState(4);
  const [bulkDuration, setBulkDuration] = useState(300); // Default 5m

  const intervalRef = useRef<number | null>(null);

  // --- Wake Lock ---
  useWakeLock(isRunning && !isPaused);

  // --- Initialize ---
  useEffect(() => {
    // Load from local storage
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
        try {
            setSavedSequences(JSON.parse(saved));
        } catch (e) {
            console.error("Failed to parse saved sequences");
        }
    }

    // Handle responsive resize for saved flows list
    const handleResize = () => {
        // Tailwind 'sm' breakpoint is 640px
        if (window.innerWidth >= 640) {
            setCollapsedCount(3);
        } else {
            setCollapsedCount(2);
        }
    };

    handleResize(); // Initial set
    window.addEventListener('resize', handleResize);

    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- Timer Logic ---
  useEffect(() => {
    if (isRunning && !isPaused) {
      intervalRef.current = window.setInterval(() => {
        setTimeLeft((prev) => {
          if (prev <= 1) {
            // Step Finished
            playTone(soundId);
            handleNextStep();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    } else {
      if (intervalRef.current) clearInterval(intervalRef.current);
    }

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [isRunning, isPaused, activeStepIndex, steps, soundId]);

  const handleNextStep = () => {
    if (activeStepIndex < steps.length - 1) {
      // Move to next step
      const nextIndex = activeStepIndex + 1;
      setActiveStepIndex(nextIndex);
      setTimeLeft(steps[nextIndex].duration);
    } else {
      // Sequence Complete
      setIsRunning(false);
      setIsPaused(false);
      setActiveStepIndex(0);
      setTimeLeft(steps[0].duration);
    }
  };

  // --- Handlers ---
  const toggleTimer = () => {
    if (!isRunning) {
      // Starting from scratch or reset
      setIsRunning(true);
      setIsPaused(false);
      if (timeLeft === 0 || activeStepIndex === 0) { 
          // Reset time left to the first step's duration on fresh start
          setTimeLeft(steps[0].duration);
      }
    } else {
      setIsPaused(!isPaused);
    }
  };

  const resetSequence = () => {
    setIsRunning(false);
    setIsPaused(false);
    setActiveStepIndex(0);
    setTimeLeft(steps[0].duration);
  };

  const resetEditor = () => {
    if (window.confirm('Reset sequence to default?')) {
        setSteps([
            { id: '1', duration: 1500, label: 'Work' },
            { id: '2', duration: 300, label: 'Rest' },
        ]);
        setActiveStepIndex(0);
        setTimeLeft(1500);
        setIsRunning(false);
        setIsPaused(false);
    }
  };

  // --- Saving Handlers ---
  const saveCurrentSequence = () => {
      const name = window.prompt("Name your flow:", `Flow ${savedSequences.length + 1}`);
      if (!name) return;

      const newSequence: SavedSequence = {
          id: Date.now().toString(),
          name,
          steps: [...steps] // Clone current steps
      };

      const updatedList = [newSequence, ...savedSequences];
      setSavedSequences(updatedList);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedList));
  };

  const deleteSavedSequence = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      if(window.confirm("Delete this saved flow?")) {
        const updatedList = savedSequences.filter(s => s.id !== id);
        setSavedSequences(updatedList);
        localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedList));
      }
  };

  const loadSavedSequence = (saved: SavedSequence) => {
      setSteps(saved.steps);
      setActiveStepIndex(0);
      setTimeLeft(saved.steps[0].duration);
      setIsRunning(false);
      setIsPaused(false);
  };

  // --- Editor Handlers ---
  const addStep = () => {
    const newStep: SequenceStep = {
      id: Date.now().toString(),
      duration: 300,
      label: 'Focus',
    };
    setSteps([...steps, newStep]);
  };

  const removeStep = (id: string) => {
    if (steps.length <= 1) return;
    setSteps(steps.filter(s => s.id !== id));
  };

  const duplicateStep = (id: string) => {
    const index = steps.findIndex(s => s.id === id);
    if (index === -1) return;

    const stepToCopy = steps[index];
    const newStep: SequenceStep = {
        ...stepToCopy,
        id: `${Date.now()}-${Math.random()}`,
        label: stepToCopy.label
    };

    const newSteps = [...steps];
    newSteps.splice(index + 1, 0, newStep);
    setSteps(newSteps);
  };

  const moveStepUp = (index: number) => {
    if (index === 0) return;
    const newSteps = [...steps];
    // Swap current step with previous step
    [newSteps[index - 1], newSteps[index]] = [newSteps[index], newSteps[index - 1]];
    setSteps(newSteps);
  };

  const moveStepDown = (index: number) => {
    if (index === steps.length - 1) return;
    const newSteps = [...steps];
    // Swap current step with next step
    [newSteps[index], newSteps[index + 1]] = [newSteps[index + 1], newSteps[index]];
    setSteps(newSteps);
  };

  const updateStep = (id: string, updates: Partial<SequenceStep>) => {
    setSteps(steps.map(s => s.id === id ? { ...s, ...updates } : s));
  };

  const adjustStepDuration = (id: string, amount: number) => {
    const step = steps.find(s => s.id === id);
    if (step) {
      const newDuration = Math.max(10, step.duration + amount); // Min 10s
      updateStep(id, { duration: newDuration });
      // If we are editing the step currently ready to play (and not running), update preview
      if (!isRunning && steps[activeStepIndex].id === id) {
          setTimeLeft(newDuration);
      }
    }
  };

  // --- Template Handlers ---
  const loadTemplate = (type: 'yoga-3' | 'yoga-5' | 'work') => {
      const now = Date.now();
      let newSteps: SequenceStep[] = [];

      if (type === 'yoga-3') {
          newSteps = Array.from({length: 4}).map((_, i) => ({
              id: `${now}-${i}`,
              duration: 180, // 3 minutes
              label: `Flow ${i + 1}`
          }));
      } else if (type === 'yoga-5') {
          newSteps = Array.from({length: 4}).map((_, i) => ({
              id: `${now}-${i}`,
              duration: 300, // 5 minutes
              label: `Flow ${i + 1}`
          }));
      } else if (type === 'work') {
          newSteps = [
              { id: `${now}-1`, duration: 1500, label: 'Work' }, // 25 min
              { id: `${now}-2`, duration: 300, label: 'Break' } // 5 min
          ];
      }

      setSteps(newSteps);
      setActiveStepIndex(0);
      setTimeLeft(newSteps[0].duration);
      setIsRunning(false);
      setIsPaused(false);
  };

  // --- Bulk Handlers ---
  const handleBulkAdd = () => {
    const startCount = steps.length + 1;
    const newSteps: SequenceStep[] = Array.from({ length: bulkCount }).map((_, i) => ({
        id: `${Date.now()}-${i}`,
        duration: bulkDuration,
        label: `Step ${startCount + i}`,
    }));

    // Append steps instead of replacing
    setSteps([...steps, ...newSteps]);
    setIsBulkModalOpen(false);
  };

  // --- Styles ---
  // Shared with TimerView for consistency but modified for SequenceView compactness
  const controlBoxClass = "bg-gray-900/40 backdrop-blur-xl border border-white/10 p-2 sm:p-3 rounded-[1.25rem] shadow-2xl shadow-black/50";
  const glassButton = "relative h-12 w-full rounded-xl flex items-center justify-center transition-all duration-300 ease-out backdrop-blur-md border border-white/5 overflow-hidden group";
  const startBtn = `${glassButton} bg-white/10 hover:bg-white/15 border-white/10 text-green-400 hover:shadow-[0_0_20px_rgba(74,222,128,0.2)] active:scale-[0.98]`;
  const resetBtn = `${glassButton} bg-white/5 hover:bg-white/10 active:scale-[0.98] text-white/80 hover:text-white hover:border-white/20`;

  // --- Render ---

  // 1. RUNNING MODE
  if (isRunning || (activeStepIndex > 0 && isPaused)) {
    const currentStep = steps[activeStepIndex];
    const progress = currentStep.duration > 0 ? timeLeft / currentStep.duration : 0;
    const nextStep = activeStepIndex < steps.length - 1 ? steps[activeStepIndex + 1] : null;

    return (
      <div className="flex flex-col items-center h-full w-full max-w-md mx-auto relative animate-in fade-in zoom-in duration-300">

        {/* Header Indicator */}
        <div className="absolute top-0 w-full flex justify-between px-4 py-2 text-xs text-white/40 uppercase tracking-widest font-medium z-10">
            <span>Running</span>
            <span>{activeStepIndex + 1} / {steps.length}</span>
        </div>

        {/* Main Circle */}
        <div className="flex-1 min-h-0 w-full flex flex-col justify-center items-center py-2 relative">
            {/* Glow behind timer matching TimerView */}
            <div className="absolute w-[200px] h-[200px] bg-white/5 rounded-full blur-3xl pointer-events-none"></div>

            <CircularProgress progress={progress} color="text-white/90">
                <div className="text-5xl sm:text-6xl font-mono font-bold tracking-wider text-white drop-shadow-2xl">
                    {formatTime(timeLeft)}
                </div>
                <div className="text-white/50 mt-2 text-sm sm:text-base font-medium tracking-wider">
                    {currentStep.label}
                </div>
            </CircularProgress>

            {/* Next Step Preview */}
            {nextStep && (
                <div className="absolute bottom-4 flex items-center gap-2 text-white/30 text-sm">
                    <span>Next: {nextStep.label}</span>
                    <ArrowRight size={14} />
                    <span>{formatTime(nextStep.duration)}</span>
                </div>
            )}
        </div>

        {/* Controls - Matching TimerView but compact */}
        <div className="w-full px-4 pb-2 shrink-0">
            <div className={controlBoxClass}>
                <div className="flex items-center justify-center gap-3">
                    <button 
                        onClick={resetSequence}
                        className={`${resetBtn} w-14`} // Slightly smaller width
                    >
                        <RotateCcw size={18} />
                    </button>

                    <button
                        onClick={toggleTimer}
                        className={`flex-1 ${
                            isPaused 
                            ? 'bg-green-500/10 border-green-500/20 text-green-400 hover:bg-green-500/20 shadow-[0_0_15px_rgba(74,222,128,0.1)]' 
                            : 'bg-red-500/10 border-red-500/20 text-red-400 hover:bg-red-500/20 shadow-[0_0_15px_rgba(239,68,68,0.1)]'
                        } ${glassButton}`}
                    >
                        {isPaused ? <Play size={22} className="ml-1 fill-current" /> : <Pause size={22} className="fill-current" />}
                    </button>
                </div>
            </div>
        </div>
      </div>
    );
  }

  // 2. EDITOR MODE

  // Logic for display items (Responsive)
  const displaySavedSequences = isSavedListExpanded 
    ? savedSequences 
    : savedSequences.slice(0, collapsedCount);

  return (
    <div className="flex flex-col h-full w-full max-w-md mx-auto pt-2 animate-in slide-in-from-bottom-4 duration-500 relative">

      {/* Editor Header - Simplified */}
      <div className="px-4 pb-4 flex justify-between items-center relative z-10 shrink-0">
          <button 
              onClick={saveCurrentSequence}
              className="flex items-center justify-center gap-2 px-3 py-1.5 rounded-lg bg-white/5 hover:bg-white/10 text-xs font-semibold text-white/80 transition-colors border border-white/10"
              title="Save Flow"
          >
             <Save size={14} /> Save Sequence
          </button>

          <div className="flex items-center gap-2">
            <button 
                onClick={() => setIsBulkModalOpen(true)}
                className="flex items-center justify-center gap-2 px-3 py-1.5 rounded-lg bg-white/5 hover:bg-white/10 text-xs font-semibold text-white/80 transition-colors border border-white/10"
                title="Batch Add"
            >
               <Layers size={14} /> Batch
            </button>
            <button 
                onClick={addStep}
                className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-white/10 hover:bg-white/20 text-xs font-semibold text-white/90 transition-colors border border-white/10"
            >
                <Plus size={14} /> Step
            </button>
          </div>
      </div>

      {/* Template Quick Actions */}
      <div className="px-4 pb-4 flex gap-3 overflow-x-auto no-scrollbar z-10 shrink-0">
         <button 
            onClick={() => loadTemplate('yoga-3')}
            className="flex-shrink-0 flex items-center gap-2 px-3 py-2 rounded-xl bg-purple-500/10 border border-purple-500/20 hover:bg-purple-500/20 text-purple-200 text-xs font-semibold transition-all active:scale-95"
         >
            <Sparkles size={14} />
            Yoga (3m)
         </button>
         <button 
            onClick={() => loadTemplate('yoga-5')}
            className="flex-shrink-0 flex items-center gap-2 px-3 py-2 rounded-xl bg-purple-500/10 border border-purple-500/20 hover:bg-purple-500/20 text-purple-200 text-xs font-semibold transition-all active:scale-95"
         >
            <Sparkles size={14} />
            Yoga (5m)
         </button>
         <button 
            onClick={() => loadTemplate('work')}
            className="flex-shrink-0 flex items-center gap-2 px-3 py-2 rounded-xl bg-blue-500/10 border border-blue-500/20 hover:bg-blue-500/20 text-blue-200 text-xs font-semibold transition-all active:scale-95"
         >
            <Briefcase size={14} />
            Work (25/5)
         </button>
      </div>

      {/* Custom Saved Flows (Expandable) */}
      {savedSequences.length > 0 && (
          <div className="px-4 pb-2 z-10 shrink-0">
            <div className="flex items-center justify-between mb-2">
                <span className="text-xs uppercase tracking-wider text-white/40 font-bold">My Flows</span>
                {savedSequences.length > collapsedCount && (
                    <button 
                        onClick={() => setIsSavedListExpanded(!isSavedListExpanded)}
                        className="text-[10px] text-white/50 hover:text-white flex items-center gap-1 uppercase tracking-wider"
                    >
                        {isSavedListExpanded ? 'Show Less' : 'Show All'}
                        {isSavedListExpanded ? <ChevronUp size={12}/> : <ChevronDown size={12} />}
                    </button>
                )}
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                {displaySavedSequences.map((seq) => (
                    <div 
                        key={seq.id}
                        onClick={() => loadSavedSequence(seq)}
                        className="group relative flex items-center justify-between px-3 py-2 rounded-xl bg-white/5 border border-white/5 hover:bg-white/10 hover:border-white/10 transition-all cursor-pointer active:scale-[0.98]"
                    >
                        <div className="flex items-center gap-1 min-w-0 flex-1">
                            <span className="text-xs font-semibold text-white truncate">
                                {seq.name} <span className="text-white/50 font-normal">({seq.steps.length})</span>
                            </span>
                        </div>
                        <button 
                            onClick={(e) => deleteSavedSequence(e, seq.id)}
                            className="shrink-0 p-1 text-white/20 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity ml-1"
                        >
                            <X size={12} />
                        </button>
                    </div>
                ))}
            </div>
          </div>
      )}

      {/* Bulk Add Modal */}
      {isBulkModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
           <div className="w-full max-w-sm bg-[#111] border border-white/10 rounded-3xl p-6 shadow-2xl animate-in zoom-in-95 duration-200">

              <div className="flex justify-between items-center mb-6">
                 <h3 className="text-lg font-bold text-white">Batch Add Steps</h3>
                 <button onClick={() => setIsBulkModalOpen(false)} className="p-2 text-white/40 hover:text-white rounded-full hover:bg-white/10 transition-colors">
                    <X size={20} />
                 </button>
              </div>

              <div className="space-y-6">
                {/* Steps Count */}
                <div>
                   <label className="text-xs uppercase tracking-wider text-white/50 font-medium mb-3 block">Number of Steps</label>
                   <div className="flex items-center justify-between bg-white/5 rounded-2xl p-2 border border-white/5">
                      <button onClick={() => setBulkCount(Math.max(1, bulkCount - 1))} className="w-12 h-12 flex items-center justify-center rounded-xl bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors">
                          <Minus size={18} />
                      </button>
                      <span className="text-2xl font-mono font-bold text-white">{bulkCount}</span>
                      <button onClick={() => setBulkCount(Math.min(50, bulkCount + 1))} className="w-12 h-12 flex items-center justify-center rounded-xl bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors">
                          <Plus size={18} />
                      </button>
                   </div>
                </div>

                {/* Duration */}
                <div>
                   <label className="text-xs uppercase tracking-wider text-white/50 font-medium mb-3 block">Duration per Step</label>
                   <div className="bg-white/5 rounded-2xl p-2 border border-white/5">
                        <div className="flex items-center justify-between mb-4 px-2 pt-2">
                             <button onClick={() => setBulkDuration(Math.max(60, bulkDuration - 60))} className="p-2 text-white/40 hover:text-white"><Minus size={16} /></button>
                             <span className="font-mono text-2xl font-bold text-white tracking-wider">{formatTime(bulkDuration)}</span>
                             <button onClick={() => setBulkDuration(bulkDuration + 60)} className="p-2 text-white/40 hover:text-white"><Plus size={16} /></button>
                        </div>
                        <div className="flex items-center justify-center gap-1.5 overflow-x-auto no-scrollbar pb-1">
                            {PRESETS.slice(0, 5).map((preset) => (
                                <button
                                    key={preset}
                                    onClick={() => setBulkDuration(preset)}
                                    className={`w-9 h-9 rounded-lg flex items-center justify-center text-[10px] font-medium border transition-all ${
                                        bulkDuration === preset
                                        ? 'bg-white/20 text-white border-white/20'
                                        : 'bg-white/5 text-white/30 border-white/5 hover:bg-white/10 hover:text-white/60'
                                    }`}
                                >
                                    {preset < 3600 ? `${preset / 60}m` : `${preset / 3600}h`}
                                </button>
                            ))}
                        </div>
                   </div>
                </div>

                {/* Actions */}
                <button 
                  onClick={handleBulkAdd}
                  className="w-full h-14 rounded-xl bg-white/10 hover:bg-white/15 border border-white/10 text-white font-semibold flex items-center justify-center gap-2 transition-all active:scale-[0.98] shadow-lg shadow-black/40"
                >
                    <Plus size={18} className="text-green-400" />
                    Add {bulkCount} Steps
                </button>
              </div>
           </div>
        </div>
      )}

      {/* Step Count Header (Fixed) */}
      <div className="px-6 py-2 shrink-0 z-10">
        <div className="flex items-center gap-4">
             <div className="h-[1px] flex-1 bg-gradient-to-r from-transparent via-white/10 to-white/10"></div>
             <span className="text-[10px] font-mono font-medium text-white/40 uppercase tracking-[0.2em] px-3 py-1 rounded-full bg-white/5 border border-white/5 backdrop-blur-sm shadow-sm">
                 {steps.length} Steps
             </span>
             <div className="h-[1px] flex-1 bg-gradient-to-l from-transparent via-white/10 to-white/10"></div>
        </div>
      </div>

      {/* Step List */}
      <div className="flex-1 min-h-0 overflow-y-auto no-scrollbar px-4 space-y-3 pb-4 relative z-10">
        {steps.map((step, index) => (
            <div 
                key={step.id} 
                className="group relative flex flex-col p-4 rounded-2xl bg-white/5 border border-white/5 hover:bg-white/10 hover:border-white/10 transition-all duration-300"
            >
                {/* Top Row: Index, Name, Arrows, Actions */}
                <div className="flex items-center gap-3 mb-3">
                    {/* Index Badge */}
                    <div className="w-6 h-6 shrink-0 rounded-full bg-white/10 flex items-center justify-center text-xs font-mono text-white/50">
                        {index + 1}
                    </div>

                    {/* Title Input */}
                    <input 
                        type="text" 
                        value={step.label}
                        onChange={(e) => updateStep(step.id, { label: e.target.value })}
                        className="bg-transparent border-none text-white font-medium focus:ring-0 p-0 text-base placeholder-white/20 flex-1 min-w-0"
                        placeholder="Step Name"
                    />

                    {/* Reorder Buttons (Distinct) */}
                    <div className="flex items-center gap-1 shrink-0">
                         <button 
                            onClick={() => moveStepUp(index)}
                            disabled={index === 0}
                            className={`w-7 h-7 flex items-center justify-center rounded-lg bg-white/5 hover:bg-white/15 text-white/70 disabled:opacity-20 disabled:hover:bg-white/5 transition-all ${index === 0 ? 'cursor-not-allowed' : 'active:scale-95'}`}
                            title="Move Up"
                        >
                            <ChevronUp size={16} />
                        </button>
                        <button 
                            onClick={() => moveStepDown(index)}
                            disabled={index === steps.length - 1}
                            className={`w-7 h-7 flex items-center justify-center rounded-lg bg-white/5 hover:bg-white/15 text-white/70 disabled:opacity-20 disabled:hover:bg-white/5 transition-all ${index === steps.length - 1 ? 'cursor-not-allowed' : 'active:scale-95'}`}
                            title="Move Down"
                        >
                            <ChevronDown size={16} />
                        </button>
                    </div>

                    {/* Divider */}
                    <div className="w-[1px] h-4 bg-white/10 mx-1"></div>

                    {/* Actions */}
                    <div className="flex items-center gap-1 shrink-0">
                        <button 
                            onClick={() => duplicateStep(step.id)}
                            className="text-white/20 hover:text-blue-400 transition-colors p-2 rounded-full hover:bg-white/5"
                            title="Duplicate Step"
                        >
                            <Copy size={16} />
                        </button>
                        <button 
                            onClick={() => removeStep(step.id)}
                            className={`text-white/20 hover:text-red-400 transition-colors p-2 rounded-full hover:bg-white/5 ${steps.length <= 1 ? 'opacity-0 pointer-events-none' : ''}`}
                        >
                            <Trash2 size={16} />
                        </button>
                    </div>
                </div>

                {/* Middle Row: Duration Counter */}
                <div className="flex items-center justify-between bg-black/20 rounded-xl p-1.5 mb-2 border border-white/5">
                    <button 
                        onClick={() => adjustStepDuration(step.id, -15)}
                        className="w-8 h-8 flex items-center justify-center rounded-lg bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors"
                    >
                        <Minus size={14} />
                    </button>

                    <span className="font-mono text-lg font-bold text-white/90 tracking-wider">
                        {formatTime(step.duration)}
                    </span>

                    <button 
                        onClick={() => adjustStepDuration(step.id, 15)}
                        className="w-8 h-8 flex items-center justify-center rounded-lg bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors"
                    >
                        <Plus size={14} />
                    </button>
                </div>

                {/* Bottom Row: Quick Presets */}
                <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1">
                    {PRESETS.map((preset) => (
                        <button
                            key={preset}
                            onClick={() => updateStep(step.id, { duration: preset })}
                            className={`flex-shrink-0 px-2.5 py-1 rounded-md text-[10px] font-medium border transition-all ${
                                step.duration === preset
                                ? 'bg-white/20 text-white border-white/20'
                                : 'bg-white/5 text-white/40 border-white/5 hover:bg-white/10 hover:text-white/60'
                            }`}
                        >
                            {preset < 3600 ? `${preset / 60}m` : `${preset / 3600}h`}
                        </button>
                    ))}
                </div>
            </div>
        ))}
        {/* Spacer for bottom controls */}
        <div className="h-4"></div>
      </div>

      {/* Editor Controls - Compact */}
      <div className="w-full px-4 pb-2 shrink-0 z-20">
          <div className={controlBoxClass}>
             <div className="flex items-center gap-3">
                 <button 
                    onClick={resetEditor}
                    className={`${resetBtn} w-14`}
                    title="Reset Sequence"
                 >
                    <RotateCcw size={18} />
                 </button>

                 <button
                   onClick={toggleTimer}
                   className={`${startBtn} flex-1 gap-2 font-bold tracking-wide`}
                 >
                   <Play size={22} className="fill-current" />
                   <span>START</span>
                 </button>
             </div>
          </div>
      </div>

    </div>
  );
};

export default SequenceView;

import React, { useState, useEffect, useRef } from 'react';
import Tabs from './components/Tabs';
import TimerView from './components/TimerView';
import StopwatchView from './components/StopwatchView';
import SequenceView from './components/SequenceView';
import SettingsView from './components/SettingsView';
import { Tab, SoundId } from './types';

const TABS: Tab[] = ['timer', 'sequence', 'stopwatch', 'settings'];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('timer');
  const [isLoading, setIsLoading] = useState(true);

  // Sound Preference State (Default: 'ethereal')
  const [selectedSound, setSelectedSound] = useState<SoundId>(() => {
    const saved = localStorage.getItem('chronos_sound');
    return (saved as SoundId) || 'ethereal';
  });

  const handleSoundChange = (id: SoundId) => {
    setSelectedSound(id);
    localStorage.setItem('chronos_sound', id);
  };

  // --- Swipe Logic ---
  const touchStartX = useRef<number | null>(null);
  const touchStartY = useRef<number | null>(null);

  const handleTouchStart = (e: React.TouchEvent) => {
    touchStartX.current = e.touches[0].clientX;
    touchStartY.current = e.touches[0].clientY;
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (touchStartX.current === null || touchStartY.current === null) return;

    const touchEndX = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;

    const deltaX = touchStartX.current - touchEndX;
    const deltaY = touchStartY.current - touchEndY;

    // Basic swipe thresholds
    const minSwipeDistance = 50;

    // Ensure horizontal swipe is dominant (X > Y) to avoid switching while scrolling vertically
    if (Math.abs(deltaX) > Math.abs(deltaY) && Math.abs(deltaX) > minSwipeDistance) {
      const currentIndex = TABS.indexOf(activeTab);

      if (deltaX > 0) {
        // Swipe Left -> Next Tab
        if (currentIndex < TABS.length - 1) {
             setActiveTab(TABS[currentIndex + 1]);
        }
      } else {
        // Swipe Right -> Prev Tab
        if (currentIndex > 0) {
             setActiveTab(TABS[currentIndex - 1]);
        }
      }
    }

    touchStartX.current = null;
    touchStartY.current = null;
  };

  useEffect(() => {
    if (isLoading) {
      const timer = setTimeout(() => {
        setIsLoading(false);
      }, 2000);
      return () => clearTimeout(timer);
    }
  }, [isLoading]);

  if (isLoading) {
    return (
      <div className="h-[100dvh] bg-black flex items-center justify-center animate-out fade-out duration-1000 cursor-default select-none">
        {/* Minimalist, Small, Elegant Loader */}
        <div className="flex flex-col items-center gap-4">
            <h1 className="text-xl md:text-2xl font-light tracking-[0.5em] text-white/90 font-mono animate-pulse">
            CHRONOMIND
            </h1>
        </div>
      </div>
    );
  }

  return (
    <div 
      className="h-[100dvh] bg-black text-white flex flex-col font-sans selection:bg-gray-800 overflow-hidden relative animate-in fade-in duration-700"
      onTouchStart={handleTouchStart}
      onTouchEnd={handleTouchEnd}
    >

      {/* Ambient Background Orbs for Glass Effect */}
      <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-blue-900/20 rounded-full blur-[100px] pointer-events-none"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-purple-900/20 rounded-full blur-[100px] pointer-events-none"></div>
      <div className="absolute top-[20%] right-[10%] w-[30%] h-[30%] bg-orange-900/10 rounded-full blur-[80px] pointer-events-none"></div>

      {/* Header */}
      <header className="px-6 py-4 shrink-0 flex items-center justify-between z-10">
        <div className="flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-white/80 shadow-[0_0_8px_rgba(255,255,255,0.8)]"></div>
            <h1 className="text-lg font-bold tracking-wider text-white/90 font-mono">
            CHRONO<span className="text-white/50">MIND</span>
            </h1>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 w-full max-w-lg mx-auto p-4 pb-24 relative flex flex-col min-h-0 z-10">
        {activeTab === 'timer' && (
           <TimerView soundId={selectedSound} />
        )}

        {activeTab === 'sequence' && (
           <SequenceView soundId={selectedSound} />
        )}

        {activeTab === 'stopwatch' && (
           <StopwatchView />
        )}

        {activeTab === 'settings' && (
           <SettingsView currentSound={selectedSound} onSoundChange={handleSoundChange} />
        )}
      </main>

      {/* Navigation */}
      <div className="fixed bottom-0 left-0 right-0 p-6 flex justify-center z-50 pointer-events-none bg-gradient-to-t from-black via-black/80 to-transparent">
        <div className="pointer-events-auto">
          <Tabs activeTab={activeTab} onTabChange={setActiveTab} />
        </div>
      </div>
    </div>
  );
};

export default App;
